// App.js - Main application with navigation and routing
import React from 'react';
import { BrowserRouter as Router, Routes, Route, NavLink } from 'react-router-dom';
import PatientsPage from './pages/PatientsPage';
import DoctorsPage from './pages/DoctorsPage';
import AppointmentsPage from './pages/AppointmentsPage';
import MedicalRecordsPage from './pages/MedicalRecordsPage';
import BillingPage from './pages/BillingPage';
import './App.css';

function App() {
  return (
    <Router>
      <div className="app">
        {/* ---- NAVIGATION BAR ---- */}
        <nav className="navbar">
          <div className="nav-brand">
            <span className="nav-icon">🏥</span>
            <span>Hospital Management System</span>
          </div>
          <div className="nav-links">
            <NavLink to="/" end className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
              👤 Patients
            </NavLink>
            <NavLink to="/doctors" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
              👨‍⚕️ Doctors
            </NavLink>
            <NavLink to="/appointments" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
              📅 Appointments
            </NavLink>
            <NavLink to="/medical-records" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
              📋 Medical Records
            </NavLink>
            <NavLink to="/billing" className={({ isActive }) => isActive ? 'nav-link active' : 'nav-link'}>
              💳 Billing
            </NavLink>
          </div>
        </nav>

        {/* ---- PAGE CONTENT (React Router) ---- */}
        <main className="main-content">
          <Routes>
            <Route path="/" element={<PatientsPage />} />
            <Route path="/doctors" element={<DoctorsPage />} />
            <Route path="/appointments" element={<AppointmentsPage />} />
            <Route path="/medical-records" element={<MedicalRecordsPage />} />
            <Route path="/billing" element={<BillingPage />} />
          </Routes>
        </main>

        <footer className="footer">
          <p>Hospital Management System | DBMS Mini Project | SRM IST</p>
        </footer>
      </div>
    </Router>
  );
}

export default App;
